```cpp
#include <MeMCore.h>

MeUltrasonicSensor ultra(PORT_3);
MeLineFollower line(PORT_2);
MeDCMotor motorL(M1);
MeDCMotor motorR(M2);
MeRGBLed led(0, 2);

void setup() {
  Serial.begin(9600);
}

void loop() {
  float mesafe = ultra.distanceCm();
  int cizgi = line.readSensors();

  // Öncelik 1: Uçurum algılama (çizgi sensörü)
  if (cizgi == 3) {  // İki sensör de beyaz = uçurum
    motorL.run(-120);
    motorR.run(-120);
    led.setColor(0, 255, 0, 0);  // Kırmızı
    led.show();
    delay(500);
    motorL.run(120);
    motorR.run(-120);
    delay(400);
  }
  // Öncelik 2: Engel algılama
  else if (mesafe < 25 && mesafe > 0) {
    motorL.run(0);
    motorR.run(0);
    led.setColor(0, 255, 255, 0);  // Sarı
    led.show();
    delay(200);
    motorL.run(-100);
    motorR.run(100);
    delay(500);
  }
  // Normal sürüş
  else {
    motorL.run(150);
    motorR.run(150);
    led.setColor(0, 0, 255, 0);  // Yeşil
    led.show();
  }
}
```

Bu yaklaşımda çizgi sensörü masa kenarı/uçurum tespiti, ultrasonik sensör engel tespiti yapar.

Arduino modunda millis() ile multitasking:

```cpp
#include <MeMCore.h>

MeUltrasonicSensor ultra(PORT_3);
MeDCMotor motorL(M1);
MeDCMotor motorR(M2);
MeRGBLed led(0, 2);
MeBuzzer buzzer;

unsigned long oncekiLed = 0;
unsigned long oncekiSensor = 0;
unsigned long oncekiBuzzer = 0;
bool ledDurum = false;
float sonMesafe = 100;

void setup() {
  Serial.begin(9600);
}

void loop() {
  unsigned long simdi = millis();

  // Görev 1: LED yanıp sönme (500ms)
  if (simdi - oncekiLed >= 500) {
    oncekiLed = simdi;
    ledDurum = !ledDurum;
    if (ledDurum) led.setColor(0, 0, 0, 255);
    else led.setColor(0, 0, 0, 0);
    led.show();
  }

  // Görev 2: Mesafe okuma (200ms)
  if (simdi - oncekiSensor >= 200) {
    oncekiSensor = simdi;
    sonMesafe = ultra.distanceCm();
    if (sonMesafe < 20) {
      motorL.run(0); motorR.run(0);
    } else {
      motorL.run(120); motorR.run(120);
    }
  }

  // Görev 3: Yakınlık uyarı bip (1000ms)
  if (simdi - oncekiBuzzer >= 1000 && sonMesafe < 30) {
    oncekiBuzzer = simdi;
    buzzer.tone(1000, 100);
  }
}
```

delay() yerine millis() kullanarak LED, sensör ve buzzer aynı anda bağımsız çalışır.

Farklı davranış modları için state machine:

```cpp
#include <MeMCore.h>

enum RobotDurum { KESFET, ENGEL_KACIS, CIZGI_TAKIP, BEKLE };
RobotDurum durum = KESFET;

MeUltrasonicSensor ultra(PORT_3);
MeLineFollower line(PORT_2);
MeDCMotor motorL(M1);
MeDCMotor motorR(M2);
unsigned long durumZamani = 0;

void setup() { Serial.begin(9600); }

void loop() {
  float mesafe = ultra.distanceCm();
  int cizgi = line.readSensors();

  switch(durum) {
    case KESFET:
      motorL.run(130); motorR.run(130);
      if (mesafe < 20) { durum = ENGEL_KACIS; durumZamani = millis(); }
      if (cizgi != 3) { durum = CIZGI_TAKIP; }
      break;

    case ENGEL_KACIS:
      motorL.run(-120); motorR.run(120);
      if (millis() - durumZamani > 800) { durum = KESFET; }
      break;

    case CIZGI_TAKIP:
      if (cizgi == 0) { motorL.run(100); motorR.run(100); }
      else if (cizgi == 1) { motorL.run(60); motorR.run(100); }
      else if (cizgi == 2) { motorL.run(100); motorR.run(60); }
      else { durum = KESFET; }
      break;

    case BEKLE:
      motorL.run(0); motorR.run(0);
      break;
  }
}
```

State machine ile robot davranışlarını modüler ve düzenli tutabilirsin. Her durumun giriş/çıkış koşulları bellidir.

